const raw = $input.first().json['LinkedIn Profile URLs'] || '';
return raw.split('\n').map(u => u.trim()).filter(u => u)
  .map(linkedin_url => ({ json: { linkedin_url } }));

const response  = $input.first().json;
const data      = response.result || response;
const input_url = $('One Profile at a Time').first().json.linkedin_url;

if (!data || !data.name || response.status === 'error')
  return [{ json: { input_url, status: 'not_found' } }];

const currentYear = new Date().getFullYear();
const firstYear   = parseInt(data.firstRoleYear || 0);

return [{ json: {
  input_url,
  name:             data.name            || '',
  job_title:        data.jobTitle         || data.job_title || '',
  company:          data.company          || '',
  headline:         data.headline         || '',
  location:         data.location         || '',
  country:          data.country          || '',
  industry:         data.industry         || '',
  email:            data.email            || '',
  mobile:           data.mobileNumber     || '',
  connections:      data.connections      || '',
  followers:        data.followers        || '',
  is_employed:      data.isCurrentlyEmployed != null ? String(data.isCurrentlyEmployed) : '',
  is_job_seeker:    data.isJobSeeker       != null ? String(data.isJobSeeker)           : '',
  years_experience: firstYear ? String(currentYear - firstYear) : '',
  linkedin_url:     data.linkedinUrl      || input_url
}}];
